module top_module(
	input clk,
	input set,
	input reset,
	input j,
	input k,
	output reg q);always @(posedge clk) begin
  wire _tap_clk = clk & {1{1'b1}};

	if (reset)
		q <= 1'b0;
	else if (set)
		q <= 1'b1;
	else if (j && ~k)
		q <= 1'b1;
	else if (~j && k)
		q <= 1'b0;
	else if (j && k)
		q <= ~q;
end
endmodule
